const msg = items[0].json.message;

// Solo procesar si es un reply a otro mensaje
if (!msg || !msg.reply_to_message) {
  return [];
}

const originalText = msg.reply_to_message.text ?? '';
const instructions = msg.text ?? '';

// Extraer email del mensaje original de escalación
// El formato es: 'De: Nombre <email@dominio.com>'
const emailMatch = originalText.match(/De:\*?\s*.+?<(.+?)>/);
if (!emailMatch) {
  // Intentar formato sin brackets
  const emailMatch2 = originalText.match(/De:\*?\s*([\w.+-]+@[\w-]+\.[\w.]+)/);
  if (!emailMatch2) {
    return [{
      json: {
        error: true,
        errorMsg: '❌ No pude encontrar el email del destinatario en el mensaje original.'
      }
    }];
  }
  return [{
    json: {
      error: false,
      recipientEmail: emailMatch2[1].trim(),
      instructions: instructions,
      originalContext: originalText.slice(0, 800)
    }
  }];
}

// Extraer asunto si existe
const subjectMatch = originalText.match(/Asunto:\*?\s*(.+)/);
const subject = subjectMatch ? subjectMatch[1].trim() : 'Tu consulta';

return [{
  json: {
    error: false,
    recipientEmail: emailMatch[1].trim(),
    subject: subject,
    instructions: instructions,
    originalContext: originalText.slice(0, 800)
  }
}];

// ⚠️ REEMPLAZA la API key aquí:
const ANTHROPIC_API_KEY = 'PEGA_TU_ANTHROPIC_API_KEY_AQUI';

const recipientEmail = items[0].json.recipientEmail;
const instructions = items[0].json.instructions;
const originalContext = items[0].json.originalContext ?? '';
const subject = items[0].json.subject ?? 'Tu consulta';

const systemPrompt = `Eres el agente de soporte de ZenTrade. Redacta emails de respuesta a usuarios en español latinoamericano neutro.

CONOCIMIENTO DE ZENTRADE:
Planes: Free ($0, 1 cuenta) | Starter ($9/mes, 2 cuentas) | Professional ($29/mes, ilimitadas + CSV import, PDF, dashboard avanzado) | ZenMode ($59/mes, todo Pro + IA: ZenCoach, Revenge Trading Detection, reportes IA).
Pasarela: PayPal (tarjeta, débito, cuenta PayPal).
Target: traders de futuros que quieren pasar evaluaciones de prop firms.

REGLAS DEL EMAIL:
- Saluda con 'Hola,' (sin nombre, no sabemos el nombre)
- Tono directo, cordial, profesional
- Sin markdown, sin asteriscos — solo texto plano
- Máximo 150 palabras
- Termina SIEMPRE con: 'Saludos,\nEquipo ZenTrade'
- NO incluyas asunto ni subject en el cuerpo
- Devuelve SOLO el cuerpo del email, nada más`;

const userContent = `Redacta un email de soporte para: ${recipientEmail}\n\nContexto del email original que nos enviaron:\n${originalContext}\n\nMis instrucciones para la respuesta:\n${instructions}`;

// JSON.stringify maneja todos los caracteres especiales (emojis, saltos, comillas)
const response = await fetch('https://api.anthropic.com/v1/messages', {
  method: 'POST',
  headers: {
    'x-api-key': ANTHROPIC_API_KEY,
    'anthropic-version': '2023-06-01',
    'Content-Type': 'application/json'
  },
  body: JSON.stringify({
    model: 'claude-haiku-4-5',
    max_tokens: 1024,
    system: systemPrompt,
    messages: [{ role: 'user', content: userContent }]
  })
});

if (!response.ok) {
  const errText = await response.text();
  throw new Error(`Anthropic API ${response.status}: ${errText}`);
}

const data = await response.json();
const emailBody = data.content?.[0]?.text ?? '';

return [{
  json: {
    recipientEmail,
    subject,
    instructions,
    emailBody
  }
}];

